import{_ as t,c as r,o as a,ae as i}from"./chunks/framework.C_fgn-gr.js";const l="/three-tile-doc/assets/image-20240708192901949.B4HVb3DZ.png",s="/three-tile-doc/assets/image-20240708195023555.C1_nKJQb.png",h="/three-tile-doc/assets/image-20240708193035753.BFqdiR-Z.png",o="/three-tile-doc/assets/image-20240708194820946.Cd416TRP.png",n="/three-tile-doc/assets/image-1.BD3WAt85.png",g="/three-tile-doc/assets/image-2.CZhGOdOl.png",d="/three-tile-doc/assets/image-3.ufB7Z9Fh.png",m="/three-tile-doc/assets/image-5.D-mWT2Gp.png",p="/three-tile-doc/assets/image-6.mGWBBz9c.png",c="/three-tile-doc/assets/image-20240708212408563.zoEy-tZW.png",b="/three-tile-doc/assets/image-8.QPwszKk6.png",_="/three-tile-doc/assets/image-9.96z75i55.png",x="/three-tile-doc/assets/image-20240708161740228.q_bUKFR_.png",u="/three-tile-doc/assets/image-20240708161859490.AuPZMi1l.png",f="/three-tile-doc/assets/image-20240708162035091.x5YqOj_Q.png",y="/three-tile-doc/assets/image-20240708162005274.P_H0dgE6.png",j="/three-tile-doc/assets/image-20240708162232109.iTTW514r.png",k="/three-tile-doc/assets/image-20240708162315798.BOPH8h_Y.png",q="/three-tile-doc/assets/image-20240708162456709.DGQJUzJV.png",P="/three-tile-doc/assets/image-20240708162928975.DhzT1RNi.png",w="/three-tile-doc/assets/image-20240708163206668.z39lAzc8.png",D="/three-tile-doc/assets/image-20240708163314611.sDAKjh0c.png",z="/three-tile-doc/assets/image-20240708215113203.BrbcduEk.png",B="/three-tile-doc/assets/image-20240708174444216.C7zXeOfg.png",T="/three-tile-doc/assets/image-20240708174650304.BCV6lRjd.png",C="/three-tile-doc/assets/image-20240708174850505.CPtaTKVo.png",O="/three-tile-doc/assets/image-20240708174735229.D6zGzSZX.png",S="/three-tile-doc/assets/image-20240708215819970.7iDehh4X.png",K=JSON.parse('{"title":"three-tile 介绍","description":"","frontmatter":{},"headers":[],"relativePath":"introduce/index.md","filePath":"introduce/index.md","lastUpdated":1740574925000}'),A={name:"introduce/index.md"};function R(V,e,Z,G,N,E){return a(),r("div",null,e[0]||(e[0]=[i('<h1 id="three-tile-介绍" tabindex="-1">three-tile 介绍 <a class="header-anchor" href="#three-tile-介绍" aria-label="Permalink to &quot;three-tile 介绍&quot;">​</a></h1><p>three-tile 是一个开源的轻量级三维瓦片库，它基于 threejs 使用 typescript 开发，提供一个三维地形模型，能轻松给你的应用增加三维瓦片地图。</p><table tabindex="0"><thead><tr><th><img src="'+l+'" alt="image-20240708192901949"></th><th><img src="'+s+'" alt="image-20240708195023555"></th></tr></thead><tbody><tr><td><img src="'+h+'" alt="image-20240708193035753"></td><td><img src="'+o+'" alt="image-20240708194820946"></td></tr></tbody></table><p>源码：<a href="https://github.com/sxguojf/three-tile" target="_blank" rel="noreferrer">https://github.com/sxguojf/three-tile</a></p><p>示例：<a href="https://github.com/sxguojf/three-tile-example" target="_blank" rel="noreferrer">https://github.com/sxguojf/three-tile-example</a></p><h2 id="_1-three-tile-是什么" tabindex="-1">1. three-tile 是什么？ <a class="header-anchor" href="#_1-three-tile-是什么" aria-label="Permalink to &quot;1. three-tile 是什么？&quot;">​</a></h2><ul><li>three-tile 是 webgis？No，它的 gis 功能很弱，仅提供了三维地图模型和地理坐标转换功能。</li><li>three-tile 是基于 cesium、mapbox 等的二次封装吗？No，它是基于 threejs 自主实现的。</li><li>three-tile 更像是游戏开发中的 LOD 地形，但它可以使用地图服务商提供的地形和影像瓦片数据渲染地图。</li><li>three-tile 的地图被封装为一个普通的 Mesh，能轻松添加进<a href="https://threejs.org/" target="_blank" rel="noreferrer"> threejs </a>应用中。</li><li>three-tile 的核心实际与地图无关，它就是一个 LOD 模型，地图只是其典型应用之一。</li></ul><h2 id="_2-开发初衷" tabindex="-1">2. 开发初衷 <a class="header-anchor" href="#_2-开发初衷" aria-label="Permalink to &quot;2. 开发初衷&quot;">​</a></h2><ul><li><p>市面上的三维 webgis 框架不少，如<a href="https://cesiumjs.org/" target="_blank" rel="noreferrer"> cesium</a>、<a href="https://openlayers.org/" target="_blank" rel="noreferrer">MapBox.gl </a>等，功能强大，但这些地图作为重量级框架，它包揽了三维场景、摄像机、模型、灯光等一切，想深度定制难度较大，另外，它们本身占用资源太多，功能一多速度难以满足需求。</p></li><li><p>三维地形也是游戏引擎中的重要功能之一，但主流的游戏引擎地形数据要么随机生成，要么美工手工设计，地形制作工作量较大。当然，unity3d、unreal4 等游戏引擎，也有一些插件可以导入真实地形，但通用性较差，操作复杂。</p></li></ul><p><strong>是否能将真实地图数据与游戏的三维地形结合，提供一个使用瓦片地图服务的轻量级三维地形模型？好，这就是 three-tile 的开发初衷。</strong></p><h2 id="_3-3d-开发技术选型" tabindex="-1">3. 3D 开发技术选型 <a class="header-anchor" href="#_3-3d-开发技术选型" aria-label="Permalink to &quot;3. 3D 开发技术选型&quot;">​</a></h2><ul><li>webgl： web 下 3D 开发必备，但直接基于 webgl 开发很繁琐，选择一个 3D 引擎能大大节省开发时间。</li><li>threejs： 封装了 webgl，使用简单，国内具有非常好的生态。</li><li>babylonjs： 封装了 webgl，大厂出品，ts 编写，支持 webgpu，但国内生态不如 threejs。</li><li>unity3d： 游戏引擎，可用 C#、JavaScript 开发，但主要用于游戏，web 端支持较差。</li><li>unreal： 游戏引擎，主要用于游戏，只能做桌面版。</li></ul><p>综合比较，如果开发 web 版的 3d 地图，选择 threejs 和 babylon.js 更加适合，考虑个人开发影响力太小，需要借助其它框架生态，那 threejs 是首选。</p><p>当然，如果确实有需求，我觉得用 babylon 或 unity3d 也可以考虑。目前还是使用 threejs 开发。</p><h2 id="_4-典型应用场景" tabindex="-1">4. 典型应用场景 <a class="header-anchor" href="#_4-典型应用场景" aria-label="Permalink to &quot;4. 典型应用场景&quot;">​</a></h2><h3 id="_4-1-给现有应用增加地形" tabindex="-1">4.1 给现有应用增加地形 <a class="header-anchor" href="#_4-1-给现有应用增加地形" aria-label="Permalink to &quot;4.1 给现有应用增加地形&quot;">​</a></h3><p>在 threejs 示例中，大部分简单应用使用一个平面作为地面，如果能把平面换为真实地形，立马增色不少：</p><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+n+'" alt="alt text">threejs 中的傻鸟</th><th style="text-align:center;"><img src="'+g+'" alt="alt text">加上地形，让它翱翔在青藏高原</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://threejs.org/examples/#webgl_lights_hemisphere" target="_blank" rel="noreferrer">three.js examples (threejs.org)</a></td><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step3.2/index.html" target="_blank" rel="noreferrer">three-tile demo (sxguojf.github.io)</a></td></tr></tbody></table><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+d+'" alt="">threejs 中可爱的小房子</th><th style="text-align:center;"><img src="'+m+'" alt="alt text">西安南二环找块工地放上去</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://threejs.org/examples/#webgl_animation_keyframes" target="_blank" rel="noreferrer">three.js examples (threejs.org)</a></td><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step2.10/index.html" target="_blank" rel="noreferrer">three-tile demo (sxguojf.github.io)</a></td></tr></tbody></table><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+p+'" alt="alt text">threejs 中孤独的小兵兵</th><th style="text-align:center;"><img src="'+c+'" alt="image-20240708212408563">放到地图上执行任务</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://threejs.org/examples/#webgl_animation_skinning_blending" target="_blank" rel="noreferrer">three.js examples (threejs.org)</a></td><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step3.4/index.html" target="_blank" rel="noreferrer">three-tile demo (sxguojf.github.io)</a></td></tr></tbody></table><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+b+'" alt="alt text">threejs 中平淡无奇的夕阳</th><th style="text-align:center;"><img src="'+_+'" alt="alt text">加上地形才是它真正的效果</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://threejs.org/examples/#webgl_shaders_sky" target="_blank" rel="noreferrer">three.js examples (threejs.org)</a></td><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step2.11/index.html" target="_blank" rel="noreferrer">three-tile demo (sxguojf.github.io)</a></td></tr></tbody></table><p>而这一切使用 three-tile 仅需三步：</p><ol><li>定义地图数据源</li><li>创建地图模型</li><li>用地图替换原来的平面</li></ol><h3 id="_4-2-简单的-webgis" tabindex="-1">4.2 简单的 webgis <a class="header-anchor" href="#_4-2-简单的-webgis" aria-label="Permalink to &quot;4.2 简单的 webgis&quot;">​</a></h3><p>当然，你如果要把 three-tile 当做一个简单三维 gis 也未尝不可，地图模型可直接使用主流瓦片数据源，渲染出逼真的地形；提供地理坐标（经纬度海拔高度）到三维场景坐标的转换，将地图元素（模型、标签）叠加在指定位置；通过鼠标键盘控制摄像机，实现地图缩放、平移、旋转和漫游；内置 mapbox、bing、goole、arcgis、天地图、高德、腾讯等瓦片地图支持，也可以自行扩展支持其它瓦片地图服务。</p><table tabindex="0"><thead><tr><th><img src="'+x+'" alt="image-20240708161740228"></th><th><img src="'+u+'" alt="image-20240708161859490"></th><th><img src="'+f+'" alt="image-20240708162035091"></th><th><img src="'+y+'" alt="image-20240708162005274"></th></tr></thead><tbody><tr><td><img src="'+j+'" alt="image-20240708162232109"></td><td><img src="'+k+'" alt="image-20240708162315798"></td><td><img src="'+q+'" alt="image-20240708162456709"></td><td><img src="'+P+'" alt="image-20240708162928975"></td></tr></tbody></table><h3 id="_4-3-游戏开发" tabindex="-1">4.3 游戏开发 <a class="header-anchor" href="#_4-3-游戏开发" aria-label="Permalink to &quot;4.3 游戏开发&quot;">​</a></h3><p>如果你想将 three-tile 用于游戏开发，也可以试试，它完美支持 threejs 内置的各种控制器，仅更换控制器，即可实现第一人称、飞行等游戏功能，在真实地图上开战效果应该不错。由于地图是实时下载的，如果对地图加载中的空白块不爽，可以通过调整地图的数据缓存和渲染缓冲区大小参数，以空间换时间缓解这个问题。</p><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+w+'" alt="image-20240708163206668">第一人称射击</th><th style="text-align:center;"><img src="'+D+'" alt="image-20240708163314611">即时战略</th><th style="text-align:center;"><img src="'+z+'" alt="image-20240708215113203">模拟飞行</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step3.3/index.html" target="_blank" rel="noreferrer">three-tile demo</a></td><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step3.4/index.html" target="_blank" rel="noreferrer">three-tile demo</a></td><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step3.2/index.html" target="_blank" rel="noreferrer">three-tile demo</a></td></tr></tbody></table><h3 id="_4-4-数据可视化" tabindex="-1">4.4 数据可视化 <a class="header-anchor" href="#_4-4-数据可视化" aria-label="Permalink to &quot;4.4 数据可视化&quot;">​</a></h3><p>目前，three-tile 在生产环境的应用主要是数据可视化：</p><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+B+'" alt="image-20240708174444216">三维卫星云图</th><th style="text-align:center;"><img src="'+T+'" alt="image-20240708174650304">风场动画</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step5.2/index.html" target="_blank" rel="noreferrer">three-tile demo</a></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><img src="'+C+'" alt="image-20240708174850505">500hpa 高度场</td><td style="text-align:center;"><img src="'+O+'" alt="image-20240708174735229">pm2.5 体渲染</td></tr><tr><td style="text-align:center;"><a href="https://sxguojf.github.io/three-tile-example/step5.4/index.html" target="_blank" rel="noreferrer">three-tile demo</a></td><td style="text-align:center;"></td></tr></tbody></table><p><img src="'+S+'" alt=""></p><p>总之，three-tile 仅提供一个地形 Mesh，利用 threejs 的强大生态实现各种炫酷的效果。如果你是 threejs 开发者，值得一试。</p><h2 id="_5-特点" tabindex="-1">5. 特点 <a class="header-anchor" href="#_5-特点" aria-label="Permalink to &quot;5. 特点&quot;">​</a></h2><ul><li>轻量级：地图以一个三维模型方式提供，使用它不会对已有程序架构产生任何影响。</li></ul><ul><li><p>依赖少：整个框架仅有 threejs（R165）一个依赖。</p></li><li><p>速度快：对资源占用做极致优化，核显也能轻松跑到 60FPS。</p></li><li><p>使用简单：熟悉 threejs 基本上没有学习成本。</p></li><li><p>扩展性强：数据、模型、纹理、材质、渲染过程均能根据自己需要扩展和替换。</p></li></ul><h2 id="_6-局限性" tabindex="-1">6. 局限性 <a class="header-anchor" href="#_6-局限性" aria-label="Permalink to &quot;6. 局限性&quot;">​</a></h2><p>能力有限，three-tile 目前还有一些短板，期待有兴趣的开发者参与。</p><ul><li><p>地图未使用球面坐标系：为了保持库的简洁，地图模型使用笛卡尔坐标，地球并不是个球，而是投影到了平面。</p><p>为什么不做成球，一方面是为了开发简单，另一方面使用球面坐标系，threejs 内置的大部分几何体、着色器都需要修改，如 BoxGeometry，它的边不能是直线，而要与地球曲率相适应，threejs 的生态完全不适用了。开始的开发计划，就是打算做个平面地图，毕竟从太空才能看出来地球是个球，但无法满足贪婪的用户需求，好吧，搞个伪球体把多余的部分遮住，远看像个球就行了。</p></li><li><p>存在 z-fight 问题： 受计算精度影响，在远距离观察时，webgl 分不清物体的前后遮挡，即存在让所有三维开发者头痛的 z-fight 问题。</p><p>既想在数万公里看地球，又要贴地看清地面的小汽车，z-fight 不可避免，虽然可以使用 logarithmicDepthBuffer 缓解，但这个缩放范围实在太大了，上万公里高空 webgl 已经无法分清你的模型距地 0.1 公里还是 0.2 公里，它会不停闪烁。能否参考 cesium 使用分段渲染的方式解决？但 three-tile 初衷是只是做一个模型，不涉及模型外的东西，如果 z-fight 确实对你的应用影响较大，那可以试试分段渲染。</p></li></ul>',40)]))}const W=t(A,[["render",R]]);export{K as __pageData,W as default};
